var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"불필요한 저항은 그만두게나! 해적 친구들.","JPN":"無駄な抵抗はやめたまえ！　海賊の諸君。","ENG":"Resistance is futile, my pirate friends.","TWN":"放棄無意義的反抗吧！海盜朋友們。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"투항하는 자는 공격하지 않네, 그러니 안심하고 무기를 버리도록!","JPN":"投降する者には攻撃しない。だから安心して\\n武器を捨てるように！","ENG":"I won't hurt you if you surrender. Please put down your weapons when I ask nicely.","TWN":"我不會攻擊投降的人，放下武器吧！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PIRATE_FOX_A_NULL","text":{"KOREA":"이, 이런! 저희가 가진 무기는 아무 것도 먹히질 않습니다!","JPN":"そ、そんな！　我々の武器が何一つ使い物になりません！","ENG":"D-drat! No weapons we have work on that monster!","TWN":"可、可惡！我們的武器完全不起作用！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_FOX_A_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_FOX_B_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"PIRATE_FOX_B_NULL","text":{"KOREA":"이대로는 안 되겠어요, 도, 도망칠까요? 대장?","JPN":"このままじゃまずいです。に、逃げますか？　隊長？","ENG":"I-I don't think we can win. Should we run, Captain?","TWN":"這樣下去會戰敗的，還是逃，逃吧？隊長？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_FOX_A_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_FOX_B_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"흥, 내 기생충으로도 인공지능의 통제권을 빼앗아올 수 없다니 재미있군.","JPN":"フン、俺の寄生虫でも人工知能の統制権を\\n奪えないなんて、おもしれえな。","ENG":"Hmpf, I didn't know there was AI that could resist my parasites. Interesting.","TWN":"哼，竟然用我的寄生蟲也不能奪取控制權，有意思。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"뭔가 아주 특별한 보안 알고리즘을 사용하는 건가?","JPN":"何か特別なセキュリティアルゴリズムでも使ってるのか？","ENG":"Is it equipped with a special security algorithm?","TWN":"是使用了特殊的保安規則系統嗎？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"하지만 아무리 특별하다고 해도 결국 기계는 기계일 뿐이지.","JPN":"だが、いくら特別でも機械は機械でしかない。","ENG":"But no matter how special, a machine is a machine.","TWN":"但就算再怎麼特殊，機器終究只是機器。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"좀 귀찮긴 하지만......","JPN":"ちょっと面倒ではあるが……","ENG":"Even though it's a hassle...","TWN":"雖然有些麻煩……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"머리를 통제할 수 없다면, 머리가 아닌 몸 전체를 통제하면 되거든!","JPN":"頭をコントロールできないならば、頭ではなく体の方を\\nコントロールしてしまえば済む話だ！","ENG":"If I can't control the brain, I can just take over the entire body!","TWN":"如果不能控制大腦，那就控制整個身體！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"......음?","JPN":"……む？","ENG":"Mm?","TWN":"……嗯？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"이런, 문제가 생긴 것 같군.","JPN":"やれやれ、問題が生じたようだな。","ENG":"Uh-oh, I think I have a problem.","TWN":"該死，遇到麻煩了。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"자네들! 지금 당장 부상자들을 데리고 유물 보관소로 퇴각하게!","JPN":"皆の者！　今すぐケガ人を連れて遺物保管所へ\\n退却したまえ！","ENG":"Guys, you'd better take the wounded and run to the artifact storage now.","TWN":"各位！你們馬上帶著傷患撤回遺物保管所！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"갑자기 무슨 소리요?","JPN":"いきなり何を言いだすんだ？","ENG":"What are you talking about?","TWN":"你說什麼？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"덕분에 해적 놈들을 거의 소탕하기 직전인데?","JPN":"おかげで海賊どもはほぼ片づいてるぞ？","ENG":"We're almost done wiping them out.","TWN":"馬上就能剿滅敵人了呀？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"아무래도 저 친구들이 뭔가 간악한 수를 쓴 모양이야.","JPN":"どうやらあいつらが何か邪悪な手を使ったようだ。","ENG":"I'm afraid they've used some nasty trick.","TWN":"他們好像使用了某種奸計。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"내 강인한 이터니움 합금 몸체에 대한 제어권이 빠르게 상실되고 있네.","JPN":"吾輩の強靭なエタニウム合金体に対する制御権が\\n急速に失われつつある。","ENG":"I'm losing my control over my powerful eternium alloy body, even as we speak.","TWN":"我堅固的永恆之金合金身體正在快速喪失控制權。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"뭐, 뭐라고? 설마 조금 전의 아라크네처럼 해적들의 편이 되는 건가?!","JPN":"な、なんだって？　まさかさっきのアラクネのように、\\n海賊に乗っ取られるのか？","ENG":"W-what? Oh no, are you going to turn to the pirates, just like the Arachnes did?","TWN":"什、什麼？難道會像之前的阿拉克涅一樣被海盜控制？！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"그건 아닐세. 내 인공지능은 완벽히 보호되고 있네.","JPN":"いや、それはない。吾輩の人工知能は完璧に\\n守られている。","ENG":"No. My AI is perfectly safe.","TWN":"不，他們無法破解我的人工智慧。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"하지만 인공지능과 몸체를 잇는 연결회로의 기능이 멈추고 있군.","JPN":"しかし、人工知能と体を繋ぐ接続回路の機能が\\n落ちている。","ENG":"But the circuits that connect my body to my brain are slowing down.","TWN":"但是連接我的身體和人工智慧的電路正在停止運行。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"이대로라면 곧 난 가동 정지 상태가 되고 말 걸세.","JPN":"このままだと間もなく吾輩は稼働停止状態になるだろう。","ENG":"Soon, I won't be able to move anymore.","TWN":"這樣下去，我會馬上停止運行。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"그 전에 최대한 시간을 벌어볼 테니 어서 도망치도록!","JPN":"その前にできるだけ時間稼ぎをする。今すぐ退却を！","ENG":"Before that happens, I'll stall them as best as I can. Now, go!","TWN":"我會盡力爭取時間，你們趕快逃！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"크윽......","JPN":"くうっ……","ENG":"Gah!","TWN":"嚇呃……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"알겠다! 미안하지만 엄호를 부탁하지!","JPN":"わかった！　悪いが、援護を頼む！","ENG":"Okay, please do that.","TWN":"好！那就拜託你掩護了！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"도와준 일은 잊지 않겠어! 반드시 자네 회사에 연락해서 구조대를 보내도록 할 테니까!","JPN":"この恩は忘れないぞ！　必ず君の所属会社に\\n連絡して救助隊を派遣させるからな！","ENG":"I won't forget this. I'll contact your company and send help your way.","TWN":"謝謝你的幫忙！我會聯繫你們公司派遣救助隊！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"하하하! 그거 고맙군! 서두르게나!","JPN":"ハハハ！　すまんな！　さあ、急ごう！","ENG":"Hah hah! That's very thoughtful of you! Now, go!","TWN":"哈哈哈！謝謝你！抓緊時間！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};